import { revalidateTag } from "next/cache";
import { getCatalog } from "@/lib/products";

export const metadata = {
  title: "Admin Catalog",
  description: "Fast catalog browsing with background catalog refresh"
};

export default async function Page() {
  const catalog = await getCatalog();

  async function syncLatestCatalog() {
    "use server";

    revalidateTag("products", "max");
  }

  return (
    <main className="min-h-screen bg-[radial-gradient(circle_at_top,_#1f2937_0%,_#0f172a_48%,_#020617_100%)] px-6 py-10 text-slate-100">
      <div className="mx-auto flex w-full max-w-6xl flex-col gap-8">
        <header className="rounded-3xl border border-white/10 bg-white/5 p-8 shadow-2xl shadow-black/30 backdrop-blur">
          <div className="flex flex-col gap-6 lg:flex-row lg:items-end lg:justify-between">
            <div className="max-w-2xl">
              <p className="text-sm font-semibold uppercase tracking-[0.3em] text-cyan-300">
                Catalog admin
              </p>
              <h1 className="mt-3 text-4xl font-semibold tracking-tight text-white sm:text-5xl">
                Product catalog
              </h1>
              <p className="mt-4 max-w-xl text-sm leading-6 text-slate-300 sm:text-base">
                Browse the shared catalog quickly. Syncs are tagged as{" "}
                <span className="rounded bg-white/10 px-2 py-0.5 font-mono text-cyan-200">
                  products
                </span>{" "}
                and refresh in the background so operators can keep working.
              </p>
            </div>

            <form action={syncLatestCatalog} className="shrink-0">
              <button
                type="submit"
                className="inline-flex items-center justify-center rounded-full bg-cyan-400 px-5 py-3 text-sm font-semibold text-slate-950 transition hover:bg-cyan-300 focus:outline-none focus:ring-2 focus:ring-cyan-200 focus:ring-offset-2 focus:ring-offset-slate-950"
              >
                Sync latest catalog
              </button>
            </form>
          </div>

          <dl className="mt-8 grid gap-4 sm:grid-cols-3">
            <Stat label="Products" value={catalog.products.length.toString()} />
            <Stat label="Source" value={catalog.sourceLabel} />
            <Stat label="Last refresh" value={formatDate(catalog.refreshedAt)} />
          </dl>
        </header>

        <section className="overflow-hidden rounded-3xl border border-white/10 bg-slate-950/70 shadow-2xl shadow-black/25">
          <div className="border-b border-white/10 px-6 py-4">
            <h2 className="text-lg font-semibold text-white">SKU overview</h2>
            <p className="mt-1 text-sm text-slate-400">
              Cached reads use the shared `products` tag, so repeated browsing stays fast.
            </p>
          </div>

          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-white/10 text-left text-sm">
              <thead className="bg-white/5 text-slate-300">
                <tr>
                  <th className="px-6 py-4 font-medium">Product</th>
                  <th className="px-6 py-4 font-medium">Category</th>
                  <th className="px-6 py-4 font-medium">Price</th>
                  <th className="px-6 py-4 font-medium">Inventory</th>
                  <th className="px-6 py-4 font-medium">Availability</th>
                  <th className="px-6 py-4 font-medium">Updated</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/10">
                {catalog.products.map((product) => (
                  <tr key={product.id} className="bg-slate-950/20 transition hover:bg-white/[0.03]">
                    <td className="px-6 py-4">
                      <div className="font-medium text-white">{product.name}</div>
                      <div className="mt-1 font-mono text-xs uppercase tracking-[0.18em] text-slate-400">
                        {product.sku}
                      </div>
                    </td>
                    <td className="px-6 py-4 text-slate-300">{product.category}</td>
                    <td className="px-6 py-4 text-slate-200">{formatPrice(product.price)}</td>
                    <td className="px-6 py-4 text-slate-200">{product.inventory}</td>
                    <td className="px-6 py-4">
                      <StatusPill availability={product.availability} />
                    </td>
                    <td className="px-6 py-4 text-slate-400">{formatDate(product.updatedAt)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>
      </div>
    </main>
  );
}

function Stat({ label, value }: { label: string; value: string }) {
  return (
    <div className="rounded-2xl border border-white/10 bg-slate-950/40 p-4">
      <dt className="text-xs font-semibold uppercase tracking-[0.28em] text-slate-400">
        {label}
      </dt>
      <dd className="mt-2 text-lg font-semibold text-white">{value}</dd>
    </div>
  );
}

function StatusPill({ availability }: { availability: string }) {
  const tone =
    availability === "In stock"
      ? "bg-emerald-400/15 text-emerald-300 ring-emerald-400/30"
      : availability === "Low stock"
        ? "bg-amber-400/15 text-amber-200 ring-amber-300/30"
        : "bg-rose-400/15 text-rose-200 ring-rose-300/30";

  return (
    <span className={`inline-flex rounded-full px-3 py-1 text-xs font-semibold ring-1 ${tone}`}>
      {availability}
    </span>
  );
}

function formatPrice(price: number) {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
    maximumFractionDigits: 0
  }).format(price);
}

function formatDate(iso: string) {
  return new Intl.DateTimeFormat("en-US", {
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit"
  }).format(new Date(iso));
}

